import React from 'react'
import SearchIcon from '@mui/icons-material/Search';
import logo from './Robectron.png';
import './Header.css'




const Header = () => (
  <>
    {/* HEADER */}
    <header>
      {/* TOP HEADER */}
      <div id="top-header">
        <div className="container">
          <ul className="header-links pull-left">
            <li><a href="#"><i className="fa fa-phone"></i> +089-481-7366</a></li>
            <li><a href="#"><i className="fa fa-envelope-o"></i> info@robectron.com</a></li>
            <li><a href="#"><i className="fa fa-map-marker"></i> Roebuck Road, Dublin 14</a></li>
          </ul>
          <ul className="header-links pull-right">
            <li><a href="#"><i className="fa fa-dollar"></i> USD</a></li>
            <li><a href="#"><i className="fa fa-user-o"></i> My Account</a></li>
          </ul>
        </div>
      </div>
      {/* /TOP HEADER */}

      {/* MAIN HEADER */}
      <div id="header">
        <div className="container">
          <div className="row">
            {/* LOGO */}
            <div className="col-md-3">
              <div className="header-logo">
                <a href="#" className="logo">
                  <img src="./img/Robectron.png" alt="" width="180" height="75" />
                </a>
              </div>
            </div>
            {/* /LOGO */}

            {/* SEARCH BAR */}
            <div className="col-md-6">
              <div className="header-search">
                <form>
                  <select className="input-select">
                    <option value="0">All Categories</option>
                    <option value="1">Category 01</option>
                    <option value="2">Category 02</option>
                  </select>
                  <input className="input" placeholder="Search here" />
                  <button className="search-btn">Search</button>
                </form>
              </div>
            </div>
            {/* /SEARCH BAR */}

            {/* ACCOUNT */}
            <div className="col-md-3 clearfix">
              <div className="header-ctn">
                {/* Wishlist */}
                <div>
                  <a href="#">
                    <i className="fa fa-heart-o"></i>
                    <span>Your Wishlist</span>
                    <div className="qty">2</div>
                  </a>
                </div>
                {/* /Wishlist */}

                {/* Cart */}
                <div className="dropdown">
                  <a className="dropdown-toggle" data-toggle="dropdown" aria-expanded="true">
                    <i className="fa fa-shopping-cart"></i>
                    <span>Your Cart</span>
                    <div className="qty">3</div>
                  </a>
                  {/* ... (rest of the cart contents) */}
                </div>
                {/* /Cart */}

                {/* ... (rest of the contents) */}
              </div>
            </div>
            {/* /ACCOUNT */}
          </div>
        </div>
      </div>
      {/* /MAIN HEADER */}
    </header>

    {/* NAVIGATION */}
    <nav id="navigation">
      <div className="container">
        <div id="responsive-nav">
          <ul className="main-nav nav navbar-nav">
            <li className="active"><a href="#">Home</a></li>
            <li><a href="#">Hot Deals</a></li>
            {/* ... (rest of the navigation links) */}
          </ul>
        </div>
      </div>
    </nav>
    {/* /NAVIGATION */}
  </>
);

export default Header;


